        {"title": "实现缺陷预测模型", "description": "编写函数predict_defect(code_metrics)，基于代码指标预测缺陷概率。\n\ncode_metrics: {complexity, lines, changes}\n返回缺陷概率(0-1)", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "缺陷预测模型", "code_template": "def predict_defect(code_metrics):\n    pass", "test_cases": "[{\"input\": \"{complexity:10,lines:500,changes:5}\", \"expected\": \"0.3\"}]", "solution": "def predict_defect(code_metrics):\n    score = (code_metrics[complexity] * 0.4 + code_metrics[lines] / 1000 * 0.3 + code_metrics[changes] * 0.3)\n    return min(score / 10, 1.0)", "hint": "加权计算各指标的贡献"},
        {"title": "实现测试用例自动生成器", "description": "编写函数generate_test_cases(function_spec)，根据函数规格生成测试用例。\n\nfunction_spec: {name, params, return_type}\n返回生成的测试用例列表", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "hard", "category": "AI测试", "knowledge_point": "智能用例生成", "code_template": "def generate_test_cases(function_spec):\n    pass", "test_cases": "[{\"input\": \"{name:add,params:[int,int],return:int}\", \"expected\": \"test cases\"}]", "solution": "def generate_test_cases(function_spec):\n    cases = []\n    for param in function_spec[params]:\n        cases.append({input: [0, 0], expected: 0})\n        cases.append({input: [1, 1], expected: 2})\n        cases.append({input: [-1, 1], expected: 0})\n    return cases", "hint": "为每种类型生成边界值和典型值"},
        {"title": "实现相似度计算器", "description": "编写函数calculate_similarity(text1, text2)，计算两个文本的相似度。\n\n使用词级Jaccard相似度", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "NLP在测试中的应用", "code_template": "def calculate_similarity(text1, text2):\n    pass", "test_cases": "[{\"input\": \"hello world, hello python\", \"expected\": \"0.33\"}]", "solution": "def calculate_similarity(text1, text2):\n    set1 = set(text1.lower().split())\n    set2 = set(text2.lower().split())\n    intersection = len(set1 & set2)\n    union = len(set1 | set2)\n    return round(intersection / union, 2) if union > 0 else 0", "hint": "Jaccard = 交集/并集"},
        {"title": "实现异常检测器", "description": "编写函数detect_anomaly(values, threshold)，检测数值序列中的异常值。\n\n异常: 超过均值+threshold*标准差", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "机器学习基础", "code_template": "def detect_anomaly(values, threshold):\n    pass", "test_cases": "[{\"input\": \"[10,12,11,100,13], 2\", \"expected\": \"[100]\"}]", "solution": "def detect_anomaly(values, threshold):\n    import statistics\n    mean = statistics.mean(values)\n    std = statistics.stdev(values)\n    return [v for v in values if abs(v - mean) > threshold * std]", "hint": "计算均值和标准差后判断"},
        {"title": "实现关键词提取器", "description": "编写函数extract_keywords(text, top_n)，提取文本关键词。\n\n返回出现频率最高的top_n个词", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "NLP在测试中的应用", "code_template": "def extract_keywords(text, top_n):\n    pass", "test_cases": "[{\"input\": \"test test case test data, 2\", \"expected\": \"[test, data]\"}]", "solution": "def extract_keywords(text, top_n):\n    words = text.lower().split()\n    freq = {}\n    for w in words:\n        freq[w] = freq.get(w, 0) + 1\n    sorted_words = sorted(freq.items(), key=lambda x: x[1], reverse=True)\n    return [w for w, c in sorted_words[:top_n]]", "hint": "统计词频后排序取前N"},
        {"title": "实现测试数据生成器", "description": "编写函数generate_test_data(schema, count)，根据schema生成测试数据。\n\nschema: {field: type}\ntype: string, int, email, phone\n返回生成的数据列表", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "测试数据生成", "code_template": "def generate_test_data(schema, count):\n    pass", "test_cases": "[{\"input\": \"{name:string,age:int}, 3\", \"expected\": \"3 records\"}]", "solution": "def generate_test_data(schema, count):\n    import random\n    import string\n    result = []\n    for i in range(count):\n        record = {}\n        for field, type in schema.items():\n            if type == string: record[field] = ''.join(random.choices(string.ascii_lowercase, k=8))\n            elif type == int: record[field] = random.randint(18, 65)\n            elif type == email: record[field] = f'user{i}@test.com'\n            elif type == phone: record[field] = f'138{random.randint(10000000, 99999999)}'\n        result.append(record)\n    return result", "hint": "根据类型选择生成策略"},
        {"title": "实现代码复杂度分析器", "description": "编写函数analyze_complexity(code)，分析代码复杂度指标。\n\n返回: {cyclomatic_complexity, lines_of_code, nesting_depth}", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "hard", "category": "AI测试", "knowledge_point": "缺陷预测模型", "code_template": "def analyze_complexity(code):\n    pass", "test_cases": "[{\"input\": \"if a: if b: pass\", \"expected\": \"complexity metrics\"}]", "solution": "def analyze_complexity(code):\n    lines = code.split('\\n')\n    loc = len([l for l in lines if l.strip()])\n    complexity = code.count('if ') + code.count('for ') + code.count('while ') + 1\n    max_indent = max((len(l) - len(l.lstrip())) for l in lines if l.strip()) if lines else 0\n    return {cyclomatic_complexity: complexity, lines_of_code: loc, nesting_depth: max_indent // 4}", "hint": "统计控制流关键字和缩进深度"},
        {"title": "实现测试用例优先级排序", "description": "编写函数prioritize_by_risk(test_cases, risk_scores)，按风险排序测试用例。\n\ntest_cases: list of {name, module}\nrisk_scores: dict {module: score}\n返回按风险降序排列的用例名列表", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "AI测试概念", "code_template": "def prioritize_by_risk(test_cases, risk_scores):\n    pass", "test_cases": "[{\"input\": \"[{name:T1,module:A},{name:T2,module:B}], {A:5,B:3}\", \"expected\": \"[T1, T2]\"}]", "solution": "def prioritize_by_risk(test_cases, risk_scores):\n    return sorted(test_cases, key=lambda tc: risk_scores.get(tc[module], 0), reverse=True)", "hint": "按模块风险分数排序"},
        {"title": "实现变更影响分析器", "description": "编写函数analyze_change_impact(changed_files, dependencies)，分析变更影响。\n\n返回受影响的文件列表", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "hard", "category": "AI测试", "knowledge_point": "AI测试概念", "code_template": "def analyze_change_impact(changed_files, dependencies):\n    pass", "test_cases": "[{\"input\": \"[A], {A:[B,C], B:[D]}\", \"expected\": \"[B, C, D]\"}]", "solution": "def analyze_change_impact(changed_files, dependencies):\n    impacted = set()\n    queue = list(changed_files)\n    while queue:\n        f = queue.pop(0)\n        for dep in dependencies.get(f, []):\n            if dep not in impacted:\n                impacted.add(dep)\n                queue.append(dep)\n    return list(impacted)", "hint": "BFS遍历依赖图"},
        {"title": "实现缺陷根本原因分类器", "description": "编写函数classify_root_cause_ai(description)，AI分类缺陷根因。\n\ncode_logic/config/environment/requirement/unknown", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "缺陷预测模型", "code_template": "def classify_root_cause_ai(description):\n    pass", "test_cases": "[{\"input\": \"空指针异常\", \"expected\": \"code_logic\"}]", "solution": "def classify_root_cause_ai(description):\n    lower = description.lower()\n    if any(w in lower for w in ['空指针', 'index', '类型', '逻辑']): return code_logic\n    if any(w in lower for w in ['配置', '环境', '版本']): return config\n    if any(w in lower for w in ['需求', '规格', '设计']): return requirement\n    return unknown", "hint": "关键词匹配分类"},
        {"title": "实现测试覆盖率预测器", "description": "编写函数predict_coverage(test_cases_count, code_lines)，预测覆盖率。\n\n基于历史数据的简单线性模型", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "AI测试概念", "code_template": "def predict_coverage(test_cases_count, code_lines):\n    pass", "test_cases": "[{\"input\": \"50, 1000\", \"expected\": \"75.0\"}]", "solution": "def predict_coverage(test_cases_count, code_lines):\n    ratio = test_cases_count / (code_lines / 10)\n    return min(round(ratio * 100, 1), 100)", "hint": "用例数与代码行数的比值"},
        {"title": "实现自然语言到测试步骤转换", "description": "编写函数nl_to_steps(natural_language)，将自然语言转为测试步骤。\n\n返回结构化的步骤列表", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "hard", "category": "AI测试", "knowledge_point": "NLP在测试中的应用", "code_template": "def nl_to_steps(natural_language):\n    pass", "test_cases": "[{\"input\": \"打开登录页面，输入用户名密码，点击登录\", \"expected\": \"[step1, step2, step3]\"}]", "solution": "def nl_to_steps(natural_language):\n    separators = ['，', '。', '、', ',', ';', '；']\n    text = natural_language\n    for sep in separators:\n        text = text.replace(sep, '|')\n    steps = [s.strip() for s in text.split('|') if s.strip()]\n    return [{step: i+1, action: s} for i, s in enumerate(steps)]", "hint": "按分隔符分割为步骤"},
        {"title": "实现测试结果趋势预测", "description": "编写函数predict_trend(historical_data, future_days)，预测测试结果趋势。\n\nhistorical_data: list of {day, pass_rate}\n返回预测的未来pass_rate列表", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "hard", "category": "AI测试", "knowledge_point": "机器学习基础", "code_template": "def predict_trend(historical_data, future_days):\n    pass", "test_cases": "[{\"input\": \"[{day:1,rate:80},{day:2,rate:85}], 3\", \"expected\": \"[87, 89, 91]\"}]", "solution": "def predict_trend(historical_data, future_days):\n    rates = [d[pass_rate] for d in historical_data]\n    if len(rates) < 2: return rates * future_days\n    avg_change = (rates[-1] - rates[0]) / (len(rates) - 1)\n    predictions = [rates[-1] + avg_change * (i + 1) for i in range(future_days)]\n    return [min(max(round(p, 1), 0), 100) for p in predictions]", "hint": "使用线性趋势外推"},
        {"title": "实现智能断言生成器", "description": "编写函数generate_assertion(response)，根据API响应自动生成断言。\n\nresponse: dict\n返回断言规则列表", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "hard", "category": "AI测试", "knowledge_point": "智能用例生成", "code_template": "def generate_assertion(response):\n    pass", "test_cases": "[{\"input\": \"{status:200,data:{name:test}}\", \"expected\": \"assertions\"}]", "solution": "def generate_assertion(response):\n    assertions = []\n    if 'status' in response:\n        assertions.append(f\"assert status == {response['status']}\")\n    if 'data' in response and isinstance(response['data'], dict):\n        for k in response['data']:\n            assertions.append(f\"assert '{k}' in response['data']\")\n    return assertions", "hint": "根据响应结构生成断言"},
        {"title": "实现测试去重器", "description": "编写函数deduplicate_tests(test_cases)，去除重复测试用例。\n\n相似度>80%视为重复\n返回去重后的用例列表", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "NLP在测试中的应用", "code_template": "def deduplicate_tests(test_cases):\n    pass", "test_cases": "[{\"input\": \"[{name:T1,desc:test login},{name:T2,desc:test login}]\", \"expected\": \"[{name:T1}]\"}]", "solution": "def deduplicate_tests(test_cases):\n    unique = []\n    for tc in test_cases:\n        is_dup = False\n        for u in unique:\n            set1 = set(tc.get('description', '').lower().split())\n            set2 = set(u.get('description', '').lower().split())\n            if set1 and set2:\n                sim = len(set1 & set2) / len(set1 | set2)\n                if sim > 0.8:\n                    is_dup = True\n                    break\n        if not is_dup:\n            unique.append(tc)\n    return unique", "hint": "计算描述文本的Jaccard相似度"},
        {"title": "实现代码变更分析器", "description": "编写函数analyze_code_changes(old_code, new_code)，分析代码变更。\n\n返回: {added_lines, removed_lines, changed_ratio}", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "AI测试概念", "code_template": "def analyze_code_changes(old_code, new_code):\n    pass", "test_cases": "[{\"input\": \"line1\\nline2, line1\\nline3\", \"expected\": \"changes analysis\"}]", "solution": "def analyze_code_changes(old_code, new_code):\n    old_lines = set(old_code.split('\\n'))\n    new_lines = set(new_code.split('\\n'))\n    added = new_lines - old_lines\n    removed = old_lines - new_lines\n    total = max(len(old_lines), len(new_lines))\n    return {added_lines: len(added), removed_lines: len(removed), changed_ratio: round((len(added) + len(removed)) / total, 2)}", "hint": "用集合运算比较差异"},
        {"title": "实现测试效率分析器", "description": "编写函数analyze_test_efficiency(test_results)，分析测试效率。\n\ntest_results: list of {name, duration, defects_found}\n返回效率指标", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "AI测试概念", "code_template": "def analyze_test_efficiency(test_results):\n    pass", "test_cases": "[{\"input\": \"[{name:T1,dur:10,defects:2},{name:T2,dur:5,defects:0}]\", \"expected\": \"efficiency metrics\"}]", "solution": "def analyze_test_efficiency(test_results):\n    total_time = sum(r[duration] for r in test_results)\n    total_defects = sum(r[defects_found] for r in test_results)\n    avg_time = total_time / len(test_results) if test_results else 0\n    defect_rate = total_defects / len(test_results) if test_results else 0\n    return {total_time: total_time, total_defects: total_defects, avg_time: avg_time, defect_rate: defect_rate}", "hint": "统计各项效率指标"},
        {"title": "实现智能测试数据边界发现", "description": "编写函数find_boundary_values(param_type, constraints)，智能发现边界值。\n\nparam_type: int/float/string\nconstraints: {min, max}\n返回边界值列表", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "测试数据生成", "code_template": "def find_boundary_values(param_type, constraints):\n    pass", "test_cases": "[{\"input\": \"int, {min:1,max:100}\", \"expected\": \"[0,1,2,99,100,101]\"}]", "solution": "def find_boundary_values(param_type, constraints):\n    min_val = constraints.get('min', 0)\n    max_val = constraints.get('max', 100)\n    return [min_val - 1, min_val, min_val + 1, max_val - 1, max_val, max_val + 1]", "hint": "边界值及相邻值"},
        {"title": "实现测试日志分析器", "description": "编写函数analyze_test_logs(logs)，分析测试日志。\n\nlogs: list of {level, message}\n返回: {errors, warnings, error_patterns}", "instructions": "请编写代码实现以下功能", "exercise_type": "code", "difficulty": "medium", "category": "AI测试", "knowledge_point": "NLP在测试中的应用", "code_template": "def analyze_test_logs(logs):\n    pass", "test_cases": "[{\"input\": \"[{level:error,msg:timeout},{level:warn,msg:slow}]\", \"expected\": \"analysis\"}]", "solution": "def analyze_test_logs(logs):\n    errors = [l for l in logs if l[level] == error]\n    warnings = [l for l in logs if l[level] == warn]\n    patterns = {}\n    for e in errors:\n        key = e[message][:20]\n        patterns[key] = patterns.get(key, 0) + 1\n    return {errors: len(errors), warnings: len(warnings), error_patterns: patterns}", "hint": "按级别统计并提取错误模式"},

